#!/usr/bin/env python3
"""
Generate drum samples for Motorik card.
Output: samples.h with const int16_t arrays scaled to ±2047.

Sound design:
- Kick: sine sweep 150→45Hz with harmonics, smooth exponential decay, 150ms
- Snare: tone + filtered noise, soft clipping, 120ms
- Hihat: ring-modulated noise for metallic character, HP filtered, 80ms
"""

import math
import random

SAMPLE_RATE = 48000
SCALE = 2047


def generate_kick():
    duration_ms = 150
    num_samples = int(SAMPLE_RATE * duration_ms / 1000)

    samples = []
    phase = 0.0

    for i in range(num_samples):
        t = i / num_samples

        # Exponential pitch sweep: 150Hz -> 45Hz
        freq = 45 + 105 * math.exp(-5 * t)

        # Phase accumulator
        phase += 2 * math.pi * freq / SAMPLE_RATE

        # Fundamental + harmonics
        fundamental = math.sin(phase)
        second_harm = 0.25 * math.sin(2 * phase)
        third_harm = 0.10 * math.sin(3 * phase)

        # Mix
        tone = fundamental + second_harm + third_harm

        # Smooth exponential decay envelope
        env = math.exp(-3.5 * t)

        # Soft clip with tanh for warmth
        sample = tone * env * 1.2
        sample = math.tanh(sample)

        samples.append(int(sample * SCALE))

    return samples


def generate_snare():
    duration_ms = 120
    num_samples = int(SAMPLE_RATE * duration_ms / 1000)

    samples = []
    tone_phase = 0.0
    # State for simple one-pole low-pass filter on noise
    noise_lp = 0.0

    for i in range(num_samples):
        t = i / num_samples

        # Tone component: ~200Hz with fast exponential decay
        tone_freq = 200
        tone_phase += 2 * math.pi * tone_freq / SAMPLE_RATE
        tone = math.sin(tone_phase) * math.exp(-8 * t)
        # Soft clip tone
        tone = math.tanh(tone * 2.0) * 0.3

        # Noise component: white noise through low-pass for bandwidth limiting
        white = random.uniform(-1, 1)
        # One-pole low-pass at ~4kHz equivalent (coefficient 0.17 at 48kHz)
        noise_lp = 0.17 * white + 0.83 * noise_lp
        # Then high-pass by subtracting previous sample (simple differencing)
        noise_hp = (
            noise_lp - (0.17 * random.uniform(-1, 1) + 0.83 * noise_lp)
            if i == 0
            else noise_lp - samples[i - 1] / SCALE
        )
        noise_hp = noise_lp * 0.83  # Simpler: just use the filtered noise directly

        # Noise envelope: starts strong, exponential decay
        noise = noise_hp * math.exp(-3.5 * t)

        # Mix: 30% tone, 70% noise
        sample = tone + noise * 0.7

        # Soft saturation
        sample = math.tanh(sample * 1.5)

        samples.append(int(sample * SCALE))

    return samples


def generate_hihat():
    duration_ms = 80
    num_samples = int(SAMPLE_RATE * duration_ms / 1000)

    samples = []
    # State for band-pass filtered noise
    bp_x1 = 0.0
    bp_y1 = 0.0

    for i in range(num_samples):
        t = i / num_samples

        # White noise
        white = random.uniform(-1, 1)

        # Band-pass filter: HP at ~2kHz, LP at ~8kHz
        # Simple two-pole resonant bandpass
        # HP stage (differentiate)
        hp = white - bp_x1
        bp_x1 = white

        # LP stage
        alpha = 0.3  # controls bandwidth
        bp_y1 = alpha * hp + (1 - alpha) * bp_y1

        # Ring modulation with metallic frequency for shimmer
        metallic_freq = 6300  # Hz
        metallic = math.sin(2 * math.pi * metallic_freq * i / SAMPLE_RATE)
        shimmer = bp_y1 * metallic

        # Fast exponential decay
        env = math.exp(-8 * t)

        # Mix bandpass and ring-modulated for richness
        sample = (bp_y1 * 0.6 + shimmer * 0.4) * env

        # Soft saturation to tame peaks
        sample = math.tanh(sample * 1.3) * 0.8

        samples.append(int(sample * SCALE))

    return samples


def write_header(kick, snare, hihat):
    with open("samples.h", "w") as f:
        f.write("#ifndef SAMPLES_H\n")
        f.write("#define SAMPLES_H\n\n")
        f.write("#include <cstdint>\n\n")
        f.write("// Drum samples for Motorik card - generated by generate_samples.py\n")
        f.write("// Sample rate: 48kHz, scaled to +/-2047 (AudioOut range)\n\n")
        f.write("namespace Samples {\n\n")

        # Kick
        f.write(f"constexpr uint32_t KICK_SAMPLES = {len(kick)};\n")
        f.write("const int16_t kick[KICK_SAMPLES] = {\n    ")
        for i, s in enumerate(kick):
            if i > 0 and i % 8 == 0:
                f.write("\n    ")
            f.write(f"{s:5d}, ")
        f.write("\n};\n\n")

        # Snare
        f.write(f"constexpr uint32_t SNARE_SAMPLES = {len(snare)};\n")
        f.write("const int16_t snare[SNARE_SAMPLES] = {\n    ")
        for i, s in enumerate(snare):
            if i > 0 and i % 8 == 0:
                f.write("\n    ")
            f.write(f"{s:5d}, ")
        f.write("\n};\n\n")

        # Hihat
        f.write(f"constexpr uint32_t HIHAT_SAMPLES = {len(hihat)};\n")
        f.write("const int16_t hihat[HIHAT_SAMPLES] = {\n    ")
        for i, s in enumerate(hihat):
            if i > 0 and i % 8 == 0:
                f.write("\n    ")
            f.write(f"{s:5d}, ")
        f.write("\n};\n\n")

        f.write("} // namespace Samples\n\n")
        f.write("#endif // SAMPLES_H\n")

    print(f"Generated samples.h:")
    print(f"  Kick:  {len(kick)} samples ({len(kick) / SAMPLE_RATE * 1000:.1f}ms)")
    print(f"  Snare: {len(snare)} samples ({len(snare) / SAMPLE_RATE * 1000:.1f}ms)")
    print(f"  Hihat: {len(hihat)} samples ({len(hihat) / SAMPLE_RATE * 1000:.1f}ms)")

    # Verify range
    for name, data in [("kick", kick), ("snare", snare), ("hihat", hihat)]:
        mn, mx = min(data), max(data)
        print(f"  {name}: range [{mn}, {mx}]")
        if mn < -32768 or mx > 32767:
            print(f"    WARNING: out of int16_t range!")
        if mn < -2048 or mx > 2047:
            print(f"    Note: exceeds AudioOut range but fine for int16_t")


if __name__ == "__main__":
    random.seed(42)

    kick = generate_kick()
    snare = generate_snare()
    hihat = generate_hihat()

    write_header(kick, snare, hihat)
    print("\nsamples.h generated successfully!")
